interface LogoProps {
  className?: string;
  width?: number;
  height?: number;
}

export default function Logo({ width = 40, height = 40 }: LogoProps) {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      version="1.1"
      width={width}
      height={height}
      viewBox={`0 0 ${width} ${height}`}
    >
      <image
        width={width}
        height={height}
        href="data:image/png;base64,"
      ></image>
    </svg>
  );
}
